mapper.select:
SELECT TRG_KUBUN AS SRC_KUBUN
      ,TRG_ID AS SRC_ID
      ,TRG_NM AS SRC_NM
      ,SRC_KUBUN AS TRG_KUBUN
      ,SRC_ID TRG_ID
      ,SRC_NM TRG_NM
      ,REL_NM
      ,'N' AS SP_YN
  FROM V_LNK_TRN_INFO
 WHERE TRG_ID= #{TRG_ID}
   AND DL_DT BETWEEN #{startDate} AND #{endDate}
   AND GNL_AC_NO =#{SRC_ID}

   AND REPLACE(SUBSTR(TRG_NM, INSTR(TRG_NM,CHR(10))+1 ), ',', '') > #{MIN_AMT}

SELECT NVL(MAX(AML_CUST_ID), COUNT(*)) AS AML_CUST_ID
  FROM NIC17B
 WHERE GNL_AC_NO = #{GNL_AC_NO}

SELECT NVL(MAX(INDV_CORP_CCD), COUNT(*)) AS INDV_CORP_CCD
  FROM NIC01B
 WHERE AML_CUST_ID = #{AML_CUST_ID}

SELECT A.AML_CUST_ID AS AML_CUST_ID ,A.RNMCNO AS RNMCNO ,A.CS_NM AS CS_NM ,A.ENG_CS_NM AS ENG_CS_NM ,GET_CODE_NAME('M002',A.RNM_CNFR_CCD) AS RNM_CNFR_CCD ,GET_CODE_NAME('M001',A.CS_ST_CD) AS CS_ST_CD ,GET_CODE_NAME('M004',A.NTN_CD) AS NTN_CD ,A.RSDNC_F AS RSDNC_F ,B.RSK_GRD_CD AS RSK_GRD_CD ,B.CS_EDD_MNG_F AS CS_EDD_MNG_F ,B.CTR_RPR_TNO AS CTR_RPR_TNO ,B.STR_RPR_TNO AS STR_RPR_TNO ,NVL(( SELECT TRIM(TO_CHAR( SUM(REPLACE(SUBSTR(TRG_NM, INSTR(TRG_NM,CHR(10))+1 ), ',', '')) , '999,999,999,999,999')) FROM V_LNK_TRN_INFO WHERE SRC_ID IN (SELECT GNL_AC_NO FROM NIC17B WHERE AML_CUST_ID=#{AML_CUST_ID, jdbcType=VARCHAR}) AND DL_DT BETWEEN #{startDate, jdbcType=VARCHAR} AND #{endDate, jdbcType=VARCHAR}
AND SP_YN='Y'
AND GNL_AC_NO IN (SELECT GNL_AC_NO FROM NIC17B WHERE AML_CUST_ID=#{AML_CUST_ID, jdbcType=VARCHAR}) AND (TRG_NM LIKE '%입금%' OR TRG_NM LIKE '%영수%') ), 0) AS INC_AMT ,NVL(( SELECT TRIM(TO_CHAR( SUM(REPLACE(SUBSTR(TRG_NM, INSTR(TRG_NM,CHR(10))+1 ), ',', '')) , '999,999,999,999,999')) FROM V_LNK_TRN_INFO WHERE SRC_ID IN (SELECT GNL_AC_NO FROM NIC17B WHERE AML_CUST_ID=#{AML_CUST_ID, jdbcType=VARCHAR}) AND DL_DT BETWEEN #{startDate, jdbcType=VARCHAR} AND #{endDate, jdbcType=VARCHAR}
AND SP_YN='Y'
AND GNL_AC_NO IN (SELECT GNL_AC_NO FROM NIC17B WHERE AML_CUST_ID=#{AML_CUST_ID, jdbcType=VARCHAR}) AND ( TRG_NM LIKE '%출금%' OR TRG_NM LIKE '%송금%' OR TRG_NM LIKE '%상환%' OR TRG_NM LIKE '%수표지급%' OR TRG_NM LIKE '%수표발행%' ) ), 0) AS DEC_AMT FROM NIC01B A , NIC35B B WHERE A.AML_CUST_ID = B.AML_CUST_ID AND A.AML_CUST_ID = #{AML_CUST_ID, jdbcType=VARCHAR}
